, 0 AS postCnt
, (SELECT COUNT(*) FROM posts WHERE USER_EMAIL = u.EMAIL) AS postCnt
FROM users u WHERE 1=1 AND u.ROLE_CODE = '01'
AND u.email like CONCAT('%', #{email}, '%')
